238→/**
239→ * Check if a dialog has been shown before
240→ * @param {string} dialogType - The dialog type to check
241→ * @returns {boolean} True if the dialog has been shown
242→ */
243→export function hasDialogBeenShown(dialogType) {
244→    return loadShownGoalDialogs().has(dialogType);
245→}
246→
247→/**
248→ * Get the dialog type(s) that should be shown for a level
249→ * @param {Array} levelGoals - Array of goal objects from level config
250→ * @returns {Array<string>} Array of dialog types that should be shown
251→ */
252→export function getDialogsToShow(levelGoals) {
253→    const dialogsToShow = [];
254→    const shownDialogs = loadShownGoalDialogs();
255→
256→    // Check each goal type in the level
257→    const goalTypes = new Set();
258→    levelGoals.forEach((goal) => {
259→        if (goal.goalType === "blocked") {
260→            // Check if this is a life-based blocked tile goal
261→            // We need to check if the level has blocked tiles with life values
262→            // This will be passed as a parameter or checked in the caller
263→            goalTypes.add("blocked");
264→        } else if (goal.goalType === "cursed") {
265→            // Check if this is an imploding cursed tile
266→            if (goal.implode) {
267→                goalTypes.add("cursed_implode");
268→            } else {
269→                goalTypes.add("cursed");
270→            }
271→        } else {
272→            goalTypes.add(goal.goalType);
273→        }
274→    });
275→
276→    // Add any new goal types that haven't been shown
277→    goalTypes.forEach((type) => {
278→        if (!shownDialogs.has(type)) {
279→            dialogsToShow.push(type);
280→        }
281→    });
282→
283→    return dialogsToShow;
284→}
285→
286→/**
287→ * Check if level has blocked tiles with life values
288→ * @param {Array} blockedTiles - Array of blocked tile configurations
289→ * @returns {boolean} True if any blocked tiles have life values
290→ */
291→export function hasLifeBasedBlockedTiles(blockedTiles) {
292→    if (!blockedTiles || blockedTiles.length === 0) return false;
293→    return blockedTiles.some((tile) => tile.lifeValue !== undefined);
294→}
295→
296→/**
297→ * Generate HTML for goal visuals to display in dialog
298→ * @param {Object} game - The game instance
299→ * @param {string} dialogType - The dialog type being shown
300→ * @returns {string} HTML string for goal visuals
301→ */
302→function generateGoalVisualsHTML(game, dialogType) {
303→    if (!game || !game.levelGoals) return "";
304→
305→    // Filter goals that match this dialog type
306→    const relevantGoals = game.levelGoals.filter((goal) => {
307→        if (dialogType === "created" && goal.goalType === "created") return true;
308→        if (dialogType === "current" && goal.goalType === "current") return true;
309→        if (dialogType === "blocked" && goal.goalType === "blocked" && !hasLifeBasedBlockedTiles(game.blockedTiles))
310→            return true;
311→        if (dialogType === "cursed" && goal.goalType === "cursed" && !goal.implode) return true;
312→        if (dialogType === "cursed_implode" && goal.goalType === "cursed" && goal.implode) return true;
313→        if (dialogType === "score" && goal.goalType === "score") return true;
314→        return false;
315→    });
316→
317→    if (relevantGoals.length === 0) return "";
318→
319→    // Generate goal cards HTML
320→    let goalsHTML = '<div class="goal-dialog-goals">';
321→    relevantGoals.forEach((goal) => (goalsHTML += createGoalCard(game, goal).outerHTML));
322→    goalsHTML += "</div>";
323→
324→    return goalsHTML;
325→}
326→
327→/**
328→ * Create and show a goal dialog
329→ * @param {string} dialogType - The type of dialog to show
330→ * @param {Object} game - The game instance (to access goals and display values)
331→ * @param {Function} onClose - Callback when dialog is closed
332→ */
333→export function showGoalDialog(dialogType, game, onClose) {
334→    const dialog = GOAL_DIALOGS[dialogType];
335→    if (!dialog) {
336→        console.error(`Unknown dialog type: ${dialogType}`);
337→        if (onClose) onClose();
338→        return;
339→    }
340→
341→    // Create dialog overlay
342→    const overlay = document.createElement("div");
343→    overlay.className = "goal-dialog-overlay";
344→    overlay.id = "goalDialog";
345→
346→    // Generate goal visuals HTML
347→    const goalsHTML = generateGoalVisualsHTML(game, dialogType);
348→
349→    // Create dialog content
350→    const dialogElement = document.createElement("div");
351→    dialogElement.className = "goal-dialog";
352→    dialogElement.innerHTML = `
353→        <div class="goal-dialog-header">
354→            <h2>${dialog.title}</h2>
355→            <h3>${dialog.subtitle}</h3>
356→        </div>
357→        <div class="goal-dialog-content">
358→            ${goalsHTML}
359→            ${dialog.content}
360→        </div>
361→        <div class="goal-dialog-footer">
362→            <button class="goal-dialog-button" id="goalDialogClose">Got it</button>
363→        </div>
364→    `;
365→
366→    overlay.appendChild(dialogElement);
367→    document.body.appendChild(overlay);
368→
369→    // Add close handler
370→    const closeButton = document.getElementById("goalDialogClose");
371→    closeButton.addEventListener("click", () => {
372→        overlay.classList.add("hidden");
373→        setTimeout(() => {
374→            overlay.remove();
375→        }, 300);
376→        saveShownGoalDialog(dialogType);
377→        if (onClose) onClose();
378→    });
379→
380→    // Show dialog with animation
381→    requestAnimationFrame(() => {
382→        overlay.classList.add("visible");
383→    });
384→}
385→
386→/**
387→ * Show multiple goal dialogs in sequence
388→ * @param {Array<string>} dialogTypes - Array of dialog types to show
389→ * @param {Object} game - The game instance
390→ * @param {Function} onComplete - Callback when all dialogs are closed
391→ */
392→export function showGoalDialogsSequence(dialogTypes, game, onComplete) {
393→    if (dialogTypes.length === 0) {
394→        if (onComplete) onComplete();
395→        return;
396→    }
397→
398→    let currentIndex = 0;
399→
400→    const showNext = () => {
401→        if (currentIndex >= dialogTypes.length) {
402→            if (onComplete) onComplete();
403→            return;
404→        }
405→
406→        showGoalDialog(dialogTypes[currentIndex], game, () => {
407→            currentIndex++;
408→            // Small delay between dialogs
409→            setTimeout(showNext, 300);
410→        });
411→    };
412→
413→    showNext();
414→}
