425→/**
426→ * Show feature unlock dialog
427→ * @param {string} featureKey - The feature key to unlock
428→ * @param {Object} game - The game instance
429→ * @param {Function} onClose - Callback when dialog is closed
430→ */
431→export function showFeatureUnlockDialog(featureKey, game, onClose) {
432→    // Resolve power_up_N keys to actual power-up type from game's selected power-ups
433→    let dialog = FEATURE_UNLOCK_DIALOGS[featureKey];
434→    if (!dialog && featureKey.startsWith("power_up_")) {
435→        const slotIndex = parseInt(featureKey.split("_")[2]) - 1;
436→        const powerUpType = game.selectedPowerUps[slotIndex];
437→        if (powerUpType) {
438→            dialog = buildPowerUpDialog(powerUpType);
439→        }
440→    }
441→    if (!dialog) {
442→        console.warn(`Unknown feature: ${featureKey}`);
443→        if (onClose) onClose();
444→        return;
445→    }
446→
447→    // Create dialog overlay
448→    const overlay = document.createElement("div");
449→    overlay.className = "goal-dialog-overlay";
450→    overlay.id = "featureUnlockDialog";
451→
452→    // Create dialog content
453→    const dialogElement = document.createElement("div");
454→    dialogElement.className = "goal-dialog";
455→    dialogElement.innerHTML = `
456→        <div class="goal-dialog-header">
457→            <h2>${dialog.title}</h2>
458→            <h3>${dialog.subtitle}</h3>
459→        </div>
460→        <div class="goal-dialog-content">
461→            ${dialog.content}
462→        </div>
463→        <div class="goal-dialog-footer">
464→            <button class="goal-dialog-button">Got it!</button>
465→        </div>
466→    `;
467→
468→    overlay.appendChild(dialogElement);
469→    document.body.appendChild(overlay);
470→
471→    // Add close handler - use querySelector on the overlay instead of getElementById
472→    const closeButton = overlay.querySelector(".goal-dialog-button");
473→    closeButton.addEventListener("click", () => {
474→        overlay.classList.add("hidden");
475→        setTimeout(() => overlay.remove(), 300);
476→        if (onClose) onClose();
477→    });
478→
479→    // Show with animation
480→    requestAnimationFrame(() => {
481→        overlay.classList.add("visible");
482→    });
483→}
