485→/**
486→ * Populate the intro dialog power-ups list based on which power-ups have been unlocked
487→ */
488→export function updateIntroDialogPowerupsList(game) {
489→    const powerupList = document.getElementById("powerupList");
490→    const powerupsSection = document.getElementById("powerupsSection");
491→    if (!powerupList || !powerupsSection) return;
492→
493→    // Clear existing list
494→    powerupList.innerHTML = "";
495→
496→    // Get visible (selected + unlocked) power-up types from game
497→    const visibleTypes = game.getVisiblePowerUpTypes();
498→
499→    if (visibleTypes.length === 0) {
500→        powerupsSection.style.display = "none";
501→        return;
502→    }
503→
504→    powerupsSection.style.display = "block";
505→
506→    visibleTypes.forEach((type) => {
507→        const info = POWER_UP_INFO[type];
508→        if (!info) return;
509→        const powerupItem = document.createElement("div");
510→        powerupItem.className = "powerup-item";
511→        powerupItem.innerHTML = `
512→            <span class="powerup-icon">${info.icon}</span>
513→            <div class="powerup-info">
514→                <strong>${info.name}</strong><br />
515→                ${info.description}
516→            </div>
517→        `;
518→        powerupList.appendChild(powerupItem);
519→    });
520→}
