 1→// Pure gravity logic - no DOM, no animation
 2→// Used by animator.js (visual) and simulation.js (headless)
 3→
 4→import { createTile, isBlocked, isBlockedWithLife, isBlockedWithMergeCount, isRectangularBlocked } from "./tile-helpers.js";
 5→import { getRandomTileValue } from "./board.js";
 6→
 7→/**
 8→ * Apply gravity to the board: tiles fall down, new tiles spawn at top.
 9→ * Mutates game.board directly.
10→ * @returns {{ movements: Array<{fromRow, row, col}>, newTiles: Array<{row, col}> }}
11→ */
12→export function applyGravity(game) {
13→    const movements = [];
14→    const newTiles = [];
15→
16→    for (let col = 0; col < game.boardWidth; col++) {
17→        // Step 1: Find immovable blocked tiles in this column
18→        const immovableBlockerPositions = [];
19→        const processedRectangles = new Set();
20→
21→        for (let row = 0; row < game.boardHeight; row++) {
22→            const tile = game.board[row][col];
23→
24→            if ((isBlocked(tile) || isBlockedWithLife(tile) || isBlockedWithMergeCount(tile)) && tile.immovable !== false) {
25→                if (isRectangularBlocked(tile)) {
26→                    if (!processedRectangles.has(tile.rectId)) {
27→                        processedRectangles.add(tile.rectId);
28→                        const { row: anchorRow } = tile.rectAnchor;
29→                        const { rectHeight } = tile;
30→                        for (let r = anchorRow; r < anchorRow + rectHeight; r++) {
31→                            immovableBlockerPositions.push(r);
32→                        }
33→                    }
34→                } else {
35→                    immovableBlockerPositions.push(row);
36→                }
37→            }
38→        }
39→
40→        // Step 2: Define sections between immovable blockers
41→        immovableBlockerPositions.sort((a, b) => a - b);
42→
43→        const sections = [];
44→        let currentSectionStart = 0;
45→
46→        for (const blockerRow of immovableBlockerPositions) {
47→            if (blockerRow > currentSectionStart) {
48→                sections.push({ start: currentSectionStart, end: blockerRow - 1 });
49→            }
50→            currentSectionStart = blockerRow + 1;
51→        }
52→
53→        if (currentSectionStart < game.boardHeight) {
54→            sections.push({ start: currentSectionStart, end: game.boardHeight - 1 });
55→        }
56→
57→        // Step 3: Apply gravity within each section
58→        let totalEmptySpaces = 0;
59→
60→        for (let sectionIndex = 0; sectionIndex < sections.length; sectionIndex++) {
61→            const section = sections[sectionIndex];
62→            let writePos = section.end;
63→            let sectionEmptyCount = 0;
64→
65→            for (let row = section.end; row >= section.start; row--) {
66→                const tile = game.board[row][col];
67→
68→                if (tile === null) {
69→                    sectionEmptyCount++;
70→                } else {
71→                    if (row !== writePos) {
72→                        movements.push({ fromRow: row, row: writePos, col });
73→                        game.board[writePos][col] = game.board[row][col];
74→                        game.board[row][col] = null;
75→                    }
76→                    writePos--;
77→                }
78→            }
79→
80→            if (sectionIndex === 0) {
81→                totalEmptySpaces = sectionEmptyCount;
82→            }
83→        }
84→
85→        // Step 4: Spawn new tiles in topmost section
86→        if (sections.length > 0 && totalEmptySpaces > 0) {
87→            const topSection = sections[0];
88→            for (let i = 0; i < totalEmptySpaces; i++) {
89→                const spawnRow = topSection.start + i;
90→                game.board[spawnRow][col] = createTile(getRandomTileValue(game));
91→                newTiles.push({ row: spawnRow, col });
92→            }
93→        }
94→    }
95→
96→    return { movements, newTiles };
97→}
