  1→// home-screen.js - Home screen management
  2→
  3→import {
  4→    saveHearts,
  5→    saveLastRegenTime,
  6→    isFeatureUnlocked,
  7→    saveUnlockedFeature,
  8→    saveStreak,
  9→    saveSuperStreak,
 10→} from "./storage.js";
 11→import { SUPER_STREAK_THRESHOLD, FEATURE_KEYS } from "./config.js";
 12→import { showFeatureUnlockDialog, hasFeatureBeenUnlocked } from "./goal-dialogs.js";
 13→
 14→/**
 15→ * Shows the home screen with current level information
 16→ * @param {Match3Game} game - The game instance
 17→ */
 18→export function showHomeScreen(game) {
 19→    const homeScreen = document.getElementById("home-screen");
 20→    const gameContainer = document.getElementById("game-container");
 21→    const levelButton = document.getElementById("start-level-button");
 22→    const streakDisplay = document.getElementById("streak-display");
 23→    const superStreakDisplay = document.getElementById("super-streak-display");
 24→    const heartsDisplay = document.getElementById("hearts-display");
 25→    const coinsDisplay = document.getElementById("coins-display");
 26→
 27→    // Regenerate hearts before showing home screen
 28→    game.regenerateHearts();
 29→
 30→    // Update button text with current level
 31→    levelButton.textContent = `Level ${game.currentLevel}`;
 32→
 33→    // Update super streak display (above regular streak) - only if feature is unlocked
 34→    if (isFeatureUnlocked(FEATURE_KEYS.SUPER_STREAK)) {
 35→        updateSuperStreakDisplay(game, superStreakDisplay);
 36→    } else {
 37→        // Hide super streak display if feature is not unlocked yet
 38→        if (superStreakDisplay) {
 39→            superStreakDisplay.innerHTML = "";
 40→        }
 41→    }
 42→
 43→    // Update streak display - only if streak feature is unlocked
 44→    if (isFeatureUnlocked(FEATURE_KEYS.STREAK)) {
 45→        updateStreakDisplay(game, streakDisplay);
 46→    } else {
 47→        // Hide streak display if feature is not unlocked yet
 48→        if (streakDisplay) {
 49→            streakDisplay.innerHTML = "";
 50→            streakDisplay.style.display = "none";
 51→        }
 52→    }
 53→
 54→    // Update hearts display
 55→    updateHeartsDisplay(game, heartsDisplay);
 56→
 57→    // Update coins display
 58→    updateCoinsDisplay(game, coinsDisplay);
 59→
 60→    // Show home screen, hide game
 61→    homeScreen.style.display = "flex";
 62→    gameContainer.style.display = "none";
 63→
 64→    // Check and show feature unlock dialogs after a short delay
 65→    checkAndShowFeatureUnlockDialogs(game);
 66→}
 67→
 68→/**
 69→ * Updates the super streak display with circular progress indicator
 70→ * @param {Match3Game} game - The game instance
 71→ * @param {HTMLElement} superStreakDisplay - The super streak display element
 72→ */
 73→function updateSuperStreakDisplay(game, superStreakDisplay) {
 74→    const superStreak = game.superStreak;
 75→    const progress = Math.min(superStreak, SUPER_STREAK_THRESHOLD);
 76→    const isActive = superStreak >= SUPER_STREAK_THRESHOLD;
 77→
 78→    // Calculate circle progress (0-283 is full circle, stroke-dasharray circumference for r=45)
 79→    const circumference = 2 * Math.PI * 45;
 80→    const progressOffset = circumference - (progress / SUPER_STREAK_THRESHOLD) * circumference;
 81→
 82→    const content = `
 83→        <div class="super-streak-container ${isActive ? "active" : ""}">
 84→            <svg class="super-streak-circle" width="120" height="120" viewBox="0 0 120 120">
 85→                <!-- Background circle -->
 86→                <circle
 87→                    cx="60"
 88→                    cy="60"
 89→                    r="45"
 90→                    fill="none"
 91→                    stroke="rgba(0, 0, 0, 0.4)"
 92→                    stroke-width="12"
 93→                />
 94→                <!-- Progress circle -->
 95→                <circle
 96→                    cx="60"
 97→                    cy="60"
 98→                    r="45"
 99→                    fill="none"
100→                    stroke="url(#superStreakGradient)"
101→                    stroke-width="8"
102→                    stroke-linecap="round"
103→                    stroke-dasharray="${circumference}"
104→                    stroke-dashoffset="${progressOffset}"
105→                    transform="translate(60, 60) rotate(-90) scale(-1, 1) translate(-60, -60)"
106→                    class="progress-circle"
107→                />
108→                <!-- Gradient definition -->
109→                <defs>
110→                    <linearGradient id="superStreakGradient" x1="0%" y1="100%" x2="100%" y2="0%">
111→                        <stop offset="0%" style="stop-color:#3E9DFF;stop-opacity:1" />
112→                        <stop offset="100%" style="stop-color:#bb00ff;stop-opacity:1" />
113→                    </linearGradient>
114→                </defs>
115→            </svg>
116→            <div class="super-streak-icon">
117→                <img src="assets/upgrade-icon_streak.png" alt="Super Streak" />
118→            </div>
119→            <div class="super-streak-text">${progress}/${SUPER_STREAK_THRESHOLD}</div>
120→        </div>
121→    `;
122→
123→    superStreakDisplay.innerHTML = content;
124→}
