324→export function handlePowerUpAction(game, row, col, element) {
325→    const tile = game.board[row][col];
326→
327→    switch (game.activePowerUp) {
328→        case "hammer":
329→            if (!tile) return;
330→            const allowedTypes = [
331→                TILE_TYPE.NORMAL,
332→                TILE_TYPE.BLOCKED_MOVABLE,
333→                TILE_TYPE.BLOCKED,
334→                TILE_TYPE.BLOCKED_WITH_LIFE,
335→            ];
336→            if (!allowedTypes.includes(tile.type)) return;
337→            usePowerUpHammer(game, row, col, element);
338→            break;
339→        case "halve":
340→            usePowerUpHalve(game, row, col, element);
341→            break;
342→        case "swap":
343→        case "teleport":
344→            return false;
345→        case "wildcard":
346→            usePowerUpWildcard(game, row, col, element);
347→            break;
348→    }
349→}
