351→export function usePowerUpHammer(game, row, col, element) {
352→    const tile = game.board[row][col];
353→
354→    game.resetHintTimer();
355→
356→    consumePowerUp(game, "hammer");
357→    updatePowerUpButtons(game);
358→
359→    track("power_up_used", {
360→        level: game.currentLevel,
361→        power_up_type: "hammer",
362→        remaining_moves: game.maxMoves - game.movesUsed,
363→        uses_remaining: getTotalPowerUpCount(game, "hammer"),
364→    });
365→
366→    game.animating = true;
367→
368→    if (isBlockedWithLife(tile)) {
369→        element.style.transition = "transform 0.3s ease, opacity 0.3s ease";
370→        element.style.opacity = "0";
371→        element.style.transform = "scale(0)";
372→
373→        setTimeout(() => {
374→            if (isRectangularBlocked(tile)) {
375→                for (let r = tile.rectAnchor.row; r < tile.rectAnchor.row + tile.rectHeight; r++) {
376→                    for (let c = tile.rectAnchor.col; c < tile.rectAnchor.col + tile.rectWidth; c++) {
377→                        if (r >= 0 && r < game.boardHeight && c >= 0 && c < game.boardWidth) {
378→                            game.board[r][c] = null;
379→                        }
380→                    }
381→                }
382→            } else {
383→                game.board[row][col] = null;
384→            }
385→
386→            game.updateBlockedTileGoals();
387→            game.dropGems();
388→            deactivatePowerUp(game);
389→        }, 300);
390→    } else if (isBlockedWithMergeCount(tile)) {
391→        let cellToClear = null;
392→        for (let r = tile.rectAnchor.row; r < tile.rectAnchor.row + tile.rectHeight; r++) {
393→            for (let c = tile.rectAnchor.col; c < tile.rectAnchor.col + tile.rectWidth; c++) {
394→                const cellKey = `${r}_${c}`;
395→                if (tile.cellMergeCounts[cellKey] > 0) {
396→                    cellToClear = { row: r, col: c, cellKey: cellKey };
397→                    break;
398→                }
399→            }
400→            if (cellToClear) break;
401→        }
402→
403→        if (cellToClear) {
404→            tile.cellMergeCounts[cellToClear.cellKey]--;
405→
406→            const allCleared = Object.values(tile.cellMergeCounts).every((count) => count === 0);
407→
408→            if (allCleared) {
409→                element.style.transition = "transform 0.3s ease, opacity 0.3s ease";
410→                element.style.opacity = "0";
411→                element.style.transform = "scale(0)";
412→
413→                setTimeout(() => {
