  1→// Board serialization and deserialization utilities
  2→//
  3→// This module provides utilities to serialize and deserialize game boards.
  4→// It supports both string-based serialization for logging/storage and
  5→// array-based presets for level configuration in config.js.
  6→//
  7→// Notation: nS=freeswap, nK=sticky_freeswap, nP=plus, nCm=cursed, B=blocked, BM=blocked_movable, Bn=blocked_with_life, J=joker, JT=wild_teleport
  8→//
  9→// Example string serialization:
 10→//   "2,4,B,2S,J|0,2P,BM,B64,2C5|1,1,1,1,1"
 11→//   This represents a 3-row board (separated by |) with 5 tiles per row (separated by ,).
 12→//
 13→// Example array preset (as used in config.js):
 14→//   [[2, 4, "B", "2S", "J"], [0, "2P", "BM", "B64", "2C5"], [1, 1, 1, 1, 1]]
 15→
 16→import { createTile, createBlockedTile, createBlockedWithLifeTile, createBlockedMovableTile, createJokerTile, createWildTeleportTile, createCursedTile, getTileValue, getTileType, isTileFreeSwapTile, isTileStickyFreeSwapTile, isTilePlusTile, isWildTeleportTile } from "./tile-helpers.js";
 17→import { TILE_TYPE } from "./config.js";
 18→
 19→/**
 20→ * Parse preset tile notation into a tile object
 21→ * @param {string|number} notation - The preset notation:
 22→ *   - Number: normal tile with that value (e.g., 2, 4, 6)
 23→ *   - "B": blocked tile
 24→ *   - "BM": blocked movable tile
 25→ *   - "B64": blocked with life value (e.g., B64 for life=64)
 26→ *   - "J": joker tile
 27→ *   - "2S": free swap tile with value 2
 28→ *   - "2K": sticky free swap tile with value 2
 29→ *   - "2P": plus tile with value 2 (can match with higher values)
 30→ *   - "2C5": cursed tile with value 2 and 5 moves remaining
 31→ * @returns {object} A tile object
 32→ */
 33→export function parsePresetTile(notation) {
 34→    if (typeof notation === "number") {
 35→        // Just a number - create a normal tile with that value
 36→        return createTile(notation);
 37→    }
 38→
 39→    const str = String(notation);
 40→
 41→    // Check for blocked tile (just "B")
 42→    if (str === "B") {
 43→        return createBlockedTile();
 44→    }
 45→
 46→    // Check for blocked movable tile (just "BM")
 47→    if (str === "BM") {
 48→        return createBlockedMovableTile();
 49→    }
 50→
 51→    // Check for wild teleport tile ("JT" - joker + teleport)
 52→    if (str === "JT") {
 53→        return createWildTeleportTile();
 54→    }
 55→
 56→    // Check for joker tile (just "J")
 57→    if (str === "J") {
 58→        return createJokerTile();
 59→    }
 60→
 61→    // Parse blocked tile with life value (e.g., "B64" for blocked with 64 life)
 62→    const blockedWithLifeMatch = str.match(/^B(\d+)$/);
 63→    if (blockedWithLifeMatch) {
 64→        const lifeValue = parseInt(blockedWithLifeMatch[1], 10);
 65→        return createBlockedWithLifeTile(lifeValue);
 66→    }
 67→
 68→    // Parse cursed tile with value and moves remaining (e.g., "2C5" for value=2, moves=5)
 69→    const cursedMatch = str.match(/^(\d+)C(\d+)$/);
 70→    if (cursedMatch) {
 71→        const value = parseInt(cursedMatch[1], 10);
 72→        const movesRemaining = parseInt(cursedMatch[2], 10);
 73→        return createCursedTile(value, movesRemaining);
 74→    }
 75→
 76→    // Parse special tiles with value prefix (e.g., "2S", "2K", "2P")
 77→    const match = str.match(/^(\d+)([SKP])$/);
 78→    if (match) {
 79→        const value = parseInt(match[1], 10);
 80→        const type = match[2];
 81→
 82→        switch (type) {
 83→            case "S": // Swap (Free swap)
 84→                return createTile(value, "freeswap");
 85→            case "K": // sticKy free swap
 86→                return createTile(value, "sticky_freeswap");
 87→            case "P": // Plus tile
 88→                return createTile(value, "plus");
 89→            default:
 90→                return createTile(value);
 91→        }
 92→    }
 93→
 94→    // If we can't parse it, return a normal tile with default value
 95→    console.warn(`Could not parse preset tile notation: ${notation}`);
 96→    return createTile(1);
 97→}
 98→
 99→/**
100→ * Convert a tile object to its notation string
101→ * @param {object} tile - The tile object
102→ * @returns {string} The notation string
103→ */
104→export function tileToNotation(tile) {
105→    if (!tile) {
106→        return "0"; // Empty cell
107→    }
108→
109→    const tileType = getTileType(tile);
110→
111→    // Handle special tile types without values
112→    if (tileType === TILE_TYPE.BLOCKED) {
113→        return "B";
114→    }
115→
116→    if (tileType === TILE_TYPE.BLOCKED_MOVABLE) {
117→        return "BM";
118→    }
119→
120→    if (tileType === TILE_TYPE.BLOCKED_WITH_LIFE) {
121→        return `B${tile.lifeValue}`;
122→    }
123→
124→    if (tileType === TILE_TYPE.JOKER) {
125→        if (isWildTeleportTile(tile)) {
126→            return "JT";
127→        }
128→        return "J";
129→    }
130→
131→    // Handle tiles with values
132→    const value = getTileValue(tile);
133→
134→    if (tileType === TILE_TYPE.CURSED) {
135→        const moves = tile.cursedMovesRemaining || 0;
136→        return `${value}C${moves}`;
137→    }
138→
139→    if (tileType === TILE_TYPE.NORMAL) {
140→        // Check for special normal tile properties
141→        if (isTileStickyFreeSwapTile(tile)) {
142→            return `${value}K`;
143→        }
144→        if (isTileFreeSwapTile(tile)) {
145→            return `${value}S`;
146→        }
147→        if (isTilePlusTile(tile)) {
148→            return `${value}P`;
149→        }
150→        // Regular normal tile
151→        return String(value);
152→    }
153→
154→    // Fallback
155→    return "0";
156→}
157→
158→/**
159→ * Serialize a 2D board array to a string
160→ * Format: "tile1,tile2,...|tile1,tile2,...|tile1,tile2,..."
161→ * Each row is separated by |, tiles within a row are separated by ,
162→ * @param {Array<Array<object>>} board - The 2D board array
163→ * @returns {string} Serialized board string
164→ */
165→export function serializeBoard(board) {
166→    if (!board || board.length === 0) {
167→        return "";
168→    }
169→
170→    const rows = board.map((row) => row.map((tile) => tileToNotation(tile)).join(","));
171→
172→    return rows.join("|");
173→}
174→
175→/**
176→ * Deserialize a board string to a 2D array
177→ * Format: "tile1,tile2,...|tile1,tile2,...|tile1,tile2,..."
178→ * @param {string} serialized - The serialized board string
179→ * @returns {Array<Array<object>>} The 2D board array
180→ */
181→export function deserializeBoard(serialized) {
182→    if (!serialized || serialized === "") {
183→        return [];
184→    }
185→
186→    const rows = serialized.split("|");
187→    const board = [];
188→
189→    for (const rowString of rows) {
190→        const rowNotations = rowString.split(",");
191→        const row = rowNotations.map((notation) => {
192→            if (notation === "0" || notation === "") {
193→                return null;
194→            }
195→            return parsePresetTile(notation);
196→        });
197→
198→        board.push(row);
199→    }
200→
201→    return board;
202→}
203→
204→/**
205→ * Convert a 2D array preset to the same 2D array format with tile objects
206→ * This is for backward compatibility with existing boardPreset arrays in config.js
207→ * @param {Array<Array<string|number>>} preset - The preset array
208→ * @returns {Array<Array<object>>} The board array with tile objects
209→ */
210→export function parsePresetArray(preset) {
211→    if (!preset || !Array.isArray(preset)) {
212→        return [];
213→    }
214→
215→    return preset.map((row) => row.map((notation) => parsePresetTile(notation)));
216→}
