  1→// Headless game simulation - no DOM, no animation
  2→// Used by MCTS/RL hint systems to evaluate moves
  3→
  4→import { applyGravity } from "./gravity.js";
  5→import { findMatches } from "./match-detector.js";
  6→import { processMerges, calculateMiddlePositions } from "./merge-processor.js";
  7→import { getDisplayValue } from "./tile-helpers.js";
  8→
  9→/**
 10→ * Deep-clone an individual tile, including nested objects.
 11→ */
 12→function cloneTile(tile) {
 13→    if (!tile) return null;
 14→    const cloned = { ...tile };
 15→    if (tile.rectAnchor && typeof tile.rectAnchor === "object") {
 16→        cloned.rectAnchor = { ...tile.rectAnchor };
 17→    }
 18→    if (tile.cellMergeCounts && typeof tile.cellMergeCounts === "object") {
 19→        cloned.cellMergeCounts = { ...tile.cellMergeCounts };
 20→    }
 21→    return cloned;
 22→}
 23→
 24→/**
 25→ * Deep-clone the board (2D array of tile objects).
 26→ */
 27→function cloneBoard(board) {
 28→    return board.map((row) => row.map((tile) => cloneTile(tile)));
 29→}
 30→
 31→/**
 32→ * Create a minimal game-like context for headless simulation.
 33→ * Copies only the fields needed by findMatches, processMerges, applyGravity.
 34→ */
 35→function createSimContext(game, board) {
 36→    return {
 37→        board,
 38→        boardWidth: game.boardWidth,
 39→        boardHeight: game.boardHeight,
 40→        tileValues: game.tileValues,
 41→        spawnableTileValues: game.spawnableTileValues,
 42→        specialTileConfig: game.specialTileConfig,
 43→        levelGoals: game.levelGoals.map((g) => ({ ...g })),
 44→        allowNonMatchingSwaps: false,
 45→        activePowerUp: null,
 46→        activatedJokerPositions: null,
 47→        powerUpOnSpecialTileUseEnabled: false,
 48→        isUserSwap: false,
 49→        lastSwapPosition: null,
 50→        movesUsed: game.movesUsed,
 51→        maxMoves: game.maxMoves,
 52→        score: 0,
 53→        animating: false,
 54→        pendingTileLevelShift: false,
 55→        cursedTileCreatedCount: { ...game.cursedTileCreatedCount },
 56→        cursedTileCreatedThisTurn: {},
 57→        shouldDecrementCursedTimers: false,
 58→        matchStats: {
 59→            tFormationCount: 0, lFormationCount: 0, blockFormationCount: 0,
 60→            match5Count: 0, match4Count: 0, match3Count: 0,
 61→        },
 62→
 63→        // Methods called by processMerges/createMergedTiles
 64→        findMatches() { return findMatches(this); },
 65→        hasMatchesForSwap(r1, c1, r2, c2) {
 66→            // Used internally - check if swap creates a match at those positions
 67→            const matches = findMatches(this);
 68→            return matches.some((match) =>
 69→                match.tiles.some((t) =>
 70→                    (t.row === r1 && t.col === c1) || (t.row === r2 && t.col === c2)
 71→                )
 72→            );
 73→        },
 74→        saveScore() {},
 75→        updateGoalDisplay() {},
 76→        updateMovesDisplay() {},
 77→        renderBoard() {},
 78→        dropGems() {},
 79→        checkAndShiftTileLevels() {},
 80→        shiftTileLevels() { return Promise.resolve(); },
 81→        checkAndGrantPowerUpReward() {},
 82→        grantRandomPowerUp() {},
 83→        grantFormationPowerUp() {},
 84→    };
 85→}
 86→
 87→/**
 88→ * Accumulate goal progress for a given tile value, filtering to "created" goals only.
 89→ */
 90→function accumulateGoal(goalProgress, levelGoals, tileValue, count) {
 91→    const hasGoal = levelGoals.some((g) => g.goalType === "created" && g.tileValue === tileValue);
 92→    if (hasGoal) {
 93→        goalProgress[tileValue] = (goalProgress[tileValue] || 0) + count;
 94→    }
 95→}
 96→
 97→/**
 98→ * Simulate a single complete move (swap → match → merge → gravity cascade).
 99→ *
100→ * @param {Match3Game} game - Live game instance (not mutated)
101→ * @param {{ row1: number, col1: number, row2: number, col2: number }} swap
102→ * @returns {{
103→ *   valid: boolean,
104→ *   newBoard: Array[][],
105→ *   scoreDelta: number,
106→ *   goalProgress: Object,
107→ *   cascades: number
108→ * }}
109→ */
110→export function simulateMove(game, swap) {
111→    const { row1, col1, row2, col2 } = swap;
112→
113→    const board = cloneBoard(game.board);
114→    const ctx = createSimContext(game, board);
115→
116→    // Swap tiles on the board
117→    const temp = ctx.board[row1][col1];
118→    ctx.board[row1][col1] = ctx.board[row2][col2];
119→    ctx.board[row2][col2] = temp;
120→
121→    ctx.lastSwapPosition = { row: row2, col: col2, movedFrom: { row: row1, col: col1 } };
122→    ctx.isUserSwap = true;
123→
124→    // Verify swap creates a match
125→    const initialMatches = findMatches(ctx);
126→    const hasMatch = initialMatches.some((match) =>
127→        match.tiles.some((t) =>
128→            (t.row === row1 && t.col === col1) || (t.row === row2 && t.col === col2)
129→        )
130→    );
131→
132→    if (!hasMatch) {
133→        // Revert and return invalid
134→        ctx.board[row2][col2] = ctx.board[row1][col1];
135→        ctx.board[row1][col1] = temp;
136→        return { valid: false, newBoard: ctx.board, scoreDelta: 0, goalProgress: {}, cascades: 0 };
137→    }
138→
139→    let scoreDelta = 0;
140→    const goalProgress = {};
141→    let cascades = 0;
142→    const maxCascades = 20;
143→
144→    // Cascade loop: find matches → merge → gravity → repeat
145→    let isFirstIteration = true;
146→    while (cascades < maxCascades) {
147→        ctx.isUserSwap = isFirstIteration;
148→
149→        const matchGroups = findMatches(ctx);
150→        if (matchGroups.length === 0) break;
151→
152→        // Accumulate score
153→        matchGroups.forEach((group) => {
154→            const displayValue = getDisplayValue(group.value);
155→            scoreDelta += displayValue * group.tiles.length;
156→        });
157→
158→        // Track goal progress — mirrors createMergedTiles logic in merge-processor.js
159→        matchGroups.forEach((group) => {
160→            const isTLFormation = group.direction === "T-formation" || group.direction === "L-formation";
161→            const is5LineFormation = group.direction === "line_5_horizontal" || group.direction === "line_5_vertical";
162→            const valueIncrement = isTLFormation || is5LineFormation ? 2 : 1;
163→            const mergedValue = group.value + valueIncrement;
164→
165→            // Count how many merged tiles are produced (1 for T/L/5-line, 2 for 4-tile line/block)
166→            const positions = isTLFormation ? [group.intersection] : calculateMiddlePositions(ctx, group.tiles, group);
167→            const tileCount = positions ? positions.length : 1;
168→
169→            // T/L/5-line: track 3 intermediate (N+1) tiles conceptually created in merge chain
170→            if (isTLFormation || is5LineFormation) {
171→                const intermediateValue = group.value + 1;
172→                accumulateGoal(goalProgress, ctx.levelGoals, intermediateValue, 3);
173→            }
174→
175→            accumulateGoal(goalProgress, ctx.levelGoals, mergedValue, tileCount);
176→        });
177→
178→        // Process merges (mutates ctx.board)
179→        processMerges(ctx, matchGroups, ctx.isUserSwap);
180→
181→        // Apply gravity (mutates ctx.board, spawns new tiles)
182→        applyGravity(ctx);
183→
184→        cascades++;
185→        isFirstIteration = false;
186→        ctx.isUserSwap = false;
187→        ctx.lastSwapPosition = null;
188→    }
189→
190→    return {
191→        valid: true,
192→        newBoard: ctx.board,
193→        scoreDelta,
194→        goalProgress,
195→        cascades,
196→    };
197→}
