  5→function getDefaultOptions() {
  6→    const nav = navigator;
  7→    const ua = nav.userAgent || "";
  8→
  9→    // Detect OS from userAgent since navigator.platform is deprecated
 10→    let os = "unknown";
 11→    if (ua.includes("Win")) os = "Windows";
 12→    else if (ua.includes("Mac")) os = "MacOS";
 13→    else if (ua.includes("Linux")) os = "Linux";
 14→    else if (ua.includes("Android")) os = "Android";
 15→    else if (ua.includes("iOS") || ua.includes("iPhone") || ua.includes("iPad")) os = "iOS";
 16→
 17→    return {
 18→        deviceInfos: {
 19→            game: "match2048",
 20→            platform: "Native",
 21→            os: os,
 22→            osVersion: ua,
 23→            browserVersion: ua,
 24→            appVersion: APP_VERSION,
 25→            bundle: "com.match2048.web",
 26→            advertisingId: null,
 27→            category: "browser",
 28→            mobileBrandName: null,
 29→            mobileModelName: null,
 30→            mobileOsHardwareModel: null,
 31→        },
 32→        userProperties: {},
 33→        userData: {},
 34→        performUserIdHashing: true,
 35→    };
 36→}
 37→
 38→function isDevelopment() {
 39→    const hostname = window.location.hostname;
 40→    const isLocalhost = hostname === "localhost" || hostname === "127.0.0.1" || hostname === "::1";
 41→    const isIPAddress = /^(\d{1,3}\.){3}\d{1,3}$/.test(hostname); // IPv4 pattern
 42→    return isLocalhost || isIPAddress;
 43→}
