 45→export function cyrb53(str, seed = 0) {
 46→    let h1 = 0xdeadbeef ^ seed,
 47→        h2 = 0x41c6ce57 ^ seed;
 48→    for (let i = 0, ch; i < str.length; i++) {
 49→        ch = str.charCodeAt(i);
 50→        h1 = Math.imul(h1 ^ ch, 2654435761);
 51→        h2 = Math.imul(h2 ^ ch, 1597334677);
 52→    }
 53→
 54→    h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507) ^ Math.imul(h2 ^ (h2 >>> 13), 3266489909);
 55→    h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507) ^ Math.imul(h1 ^ (h1 >>> 13), 3266489909);
 56→
 57→    return ((h2 >>> 0).toString(36) + (h1 >>> 0).toString(36)).padEnd(16, "0");
 58→}
 59→
 60→async function track(eventName, parameters = {}, options = {}) {
 61→    // Skip tracking in development (localhost or IP addresses)
 62→    if (isDevelopment()) {
 63→        console.log("[Tracker] Skipping tracking in development:", eventName, parameters);
 64→        return null;
 65→    }
 66→
 67→    const trackingURL = "https://octolytics.lotum.com/v3/collect";
 68→    const sessionStartTimestamp = Date.now();
 69→
 70→    // Load user ID from localStorage if not provided
 71→    const userId = loadUserId();
 72→
 73→    // Merge provided options with defaults
 74→    const defaultOptions = getDefaultOptions();
 75→    options = {
 76→        deviceInfos: { ...defaultOptions.deviceInfos, ...(options.deviceInfos || {}) },
 77→        userProperties: { ...defaultOptions.userProperties, ...(options.userProperties || {}) },
 78→        userData: { userID: userId, ...(options.userData || {}) },
 79→        performUserIdHashing:
 80→            options.performUserIdHashing !== undefined
 81→                ? options.performUserIdHashing
 82→                : defaultOptions.performUserIdHashing,
 83→    };
 84→
 85→    const hashCode = (s) => {
 86→        let h = 0;
 87→        for (let i = 0; i < s.length; i++) h = (Math.imul(31, h) + s.charCodeAt(i)) | 0;
 88→        return h.toString(36);
 89→    };
 90→
 91→    // Extract optional device/user data
 92→    const deviceInfo = options.deviceInfos || {};
 93→    const userProperties = options.userProperties || {};
 94→    const userData = options.userData || {};
 95→    const performHash = options.performUserIdHashing !== false;
 96→
 97→    const hashedUserID = userData.userID && performHash ? cyrb53(userData.userID) : userData.userID;
 98→    const userPseudoId = userData.userID ? userData.userID : generateUUID();
 99→
100→    const event = {
101→        eventTimestamp: Date.now(),
102→        tzOffset: new Date().getTimezoneOffset(),
103→        eventName,
104→        sessionStartTimestamp,
105→        game: deviceInfo.game,
106→        platform: deviceInfo.platform,
107→        os: deviceInfo.os,
108→        osVersion: deviceInfo.osVersion,
109→        browserVersion: deviceInfo.browserVersion,
110→        appVersion: deviceInfo.appVersion,
111→        bundle: deviceInfo.bundle,
112→        device: {
113→            advertisingId: deviceInfo.advertisingId,
114→            category: deviceInfo.category,
115→            mobileBrandName: deviceInfo.mobileBrandName,
116→            mobileModelName: deviceInfo.mobileModelName,
117→            mobileOsHardwareModel: deviceInfo.mobileOsHardwareModel,
118→        },
119→        userId: hashedUserID,
120→        userProperties,
121→        eventParams: parameters,
122→        consentGiven: false,
123→        eventSequenceNumber: 0,
124→        userPseudoId: userPseudoId,
125→        userFirstTouchTimestamp: Date.now(),
126→        userCreatedAt: userData.userCreatedAt,
127→    };
128→
129→    event.hash = hashCode(JSON.stringify(event));
130→
131→    // Send the event
132→    const response = await fetch(trackingURL, {
133→        method: "POST",
134→        headers: { "Content-Type": "application/json" },
135→        body: JSON.stringify(event),
136→    });
137→
138→    if (!response.ok) {
139→        console.error("Failed to send tracking event", response.status);
140→    }
141→
142→    return event;
143→}
