  1→/**
  2→ * tutorial.js
  3→ *
  4→ * FTUX (First Time User Experience) tutorial system
  5→ * Guides users through specific swap sequences with animated hand and hint text
  6→ */
  7→
  8→/**
  9→ * Initialize tutorial from level config
 10→ * @param {Match3Game} game - Game instance
 11→ */
 12→export function initTutorial(game) {
 13→    const level = game.levelConfig;
 14→
 15→    if (!level.tutorialSwaps || level.tutorialSwaps.length === 0) {
 16→        game.tutorialState = null;
 17→        return;
 18→    }
 19→
 20→    game.tutorialState = {
 21→        active: true,
 22→        currentStep: 0,
 23→        swaps: level.tutorialSwaps,
 24→    };
 25→
 26→    // Create DOM elements if they don't exist
 27→    if (!game.tutorialElements) {
 28→        const overlay = document.getElementById("tutorialOverlay");
 29→        const hand = document.getElementById("tutorialHand");
 30→        const hintBox = document.querySelector(".tutorial-hint-box");
 31→        const hintText = document.getElementById("tutorialHintText");
 32→
 33→        game.tutorialElements = {
 34→            overlay,
 35→            hand,
 36→            hintBox,
 37→            hintText,
 38→        };
 39→    }
 40→}
 41→
 42→/**
 43→ * Check if tutorial is currently active
 44→ * @param {Match3Game} game - Game instance
 45→ * @returns {boolean} True if tutorial is active
 46→ */
 47→export function isTutorialActive(game) {
 48→    return game.tutorialState && game.tutorialState.active;
 49→}
 50→
 51→/**
 52→ * Get the current tutorial swap definition
 53→ * @param {Match3Game} game - Game instance
 54→ * @returns {Object|null} Current swap object or null
 55→ */
 56→export function getCurrentTutorialSwap(game) {
 57→    if (!isTutorialActive(game)) return null;
 58→
 59→    const step = game.tutorialState.currentStep;
 60→    return game.tutorialState.swaps[step] || null;
 61→}
 62→
 63→/**
 64→ * Check if the current tutorial step is a power-up step
 65→ * @param {Match3Game} game - Game instance
 66→ * @returns {boolean} True if current step is power-up step
 67→ */
 68→export function isTutorialPowerUpStep(game) {
 69→    const currentSwap = getCurrentTutorialSwap(game);
 70→    if (!currentSwap) return false;
 71→
 72→    // Check if step has a powerUp property
 73→    return currentSwap.powerUp !== undefined;
 74→}
 75→
 76→/**
 77→ * Check if a swap matches the current tutorial step (bidirectional)
 78→ * @param {Match3Game} game - Game instance
 79→ * @param {number} row1 - First tile row
 80→ * @param {number} col1 - First tile column
 81→ * @param {number} row2 - Second tile row
 82→ * @param {number} col2 - Second tile column
 83→ * @returns {boolean} True if swap is valid for tutorial
 84→ */
 85→export function isValidTutorialSwap(game, row1, col1, row2, col2) {
 86→    const currentSwap = getCurrentTutorialSwap(game);
 87→    if (!currentSwap) return false;
 88→
 89→    // If this is a tap-only step, swapping is not valid
 90→    if (!currentSwap.from || !currentSwap.to) return false;
 91→
 92→    const from = currentSwap.from;
 93→    const to = currentSwap.to;
 94→
 95→    // Check forward direction (from → to)
 96→    const matchesForward = row1 === from.row && col1 === from.col && row2 === to.row && col2 === to.col;
 97→
 98→    // Check reverse direction (to → from)
 99→    const matchesReverse = row1 === to.row && col1 === to.col && row2 === from.row && col2 === from.col;
100→
101→    return matchesForward || matchesReverse;
102→}
103→
104→/**
105→ * Check if the current tutorial step is a tap-only step
106→ * @param {Match3Game} game - Game instance
107→ * @returns {boolean} True if current step is tap-only
108→ */
109→export function isTutorialTapStep(game) {
110→    const currentSwap = getCurrentTutorialSwap(game);
111→    if (!currentSwap) return false;
112→
113→    // Check if step has a tap property
114→    return currentSwap.tap !== undefined;
115→}
116→
117→/**
118→ * Check if a tap matches the current tutorial step
119→ * @param {Match3Game} game - Game instance
120→ * @param {number} row - Tapped tile row
121→ * @param {number} col - Tapped tile column
122→ * @returns {boolean} True if tap is valid for tutorial
123→ */
124→export function isValidTutorialTap(game, row, col) {
125→    const currentSwap = getCurrentTutorialSwap(game);
126→    if (!currentSwap) return false;
127→
128→    // Check if step has a tap property
129→    if (currentSwap.tap) {
130→        return row === currentSwap.tap.row && col === currentSwap.tap.col;
131→    }
132→
133→    return false;
134→}
135→
136→/**
137→ * Check if a tile can be dragged during tutorial
138→ * @param {Match3Game} game - Game instance
139→ * @param {number} row - Tile row
140→ * @param {number} col - Tile column
141→ * @returns {boolean} True if tile can be dragged
142→ */
143→export function canDragTileInTutorial(game, row, col) {
144→    if (!isTutorialActive(game)) return true;
145→
146→    const currentSwap = getCurrentTutorialSwap(game);
147→    if (!currentSwap) return false;
148→
149→    // If this is a power-up step, allow interaction ONLY if power-up is active
150→    // This allows clicking tiles when power-up is activated
151→    if (currentSwap.powerUp) {
152→        // If power-up is active, allow clicking the target tile
153→        if (game.activePowerUp === currentSwap.powerUp.type) {
154→            return row === currentSwap.powerUp.target.row && col === currentSwap.powerUp.target.col;
155→        }
156→        // Power-up not active yet, don't allow tile interaction
157→        return false;
158→    }
159→
160→    // If this is a tap-only step, allow selecting the tap tile (but not dragging)
161→    if (currentSwap.tap) {
162→        return row === currentSwap.tap.row && col === currentSwap.tap.col;
163→    }
164→
165→    // For swap steps, allow dragging if this is one of the tutorial tiles
166→    if (currentSwap.from && currentSwap.to) {
167→        const from = currentSwap.from;
168→        const to = currentSwap.to;
169→        return (row === from.row && col === from.col) || (row === to.row && col === to.col);
170→    }
171→
172→    return false;
173→}
174→
175→/**
176→ * Check if the tutorial expects a specific power-up to be activated
177→ * @param {Match3Game} game - Game instance
178→ * @param {string} powerUpType - Type of power-up ("hammer", "halve", "swap")
179→ * @returns {boolean} True if power-up matches tutorial
180→ */
181→export function isValidTutorialPowerUp(game, powerUpType) {
182→    const currentSwap = getCurrentTutorialSwap(game);
183→    if (!currentSwap) return false;
184→
185→    if (currentSwap.powerUp) {
186→        return currentSwap.powerUp.type === powerUpType;
187→    }
188→
189→    return false;
190→}
191→
192→/**
193→ * Check if a tile is valid for the current power-up tutorial step
194→ * @param {Match3Game} game - Game instance
195→ * @param {number} row - Tile row
196→ * @param {number} col - Tile column
197→ * @returns {boolean} True if tile is valid for tutorial power-up
198→ */
199→export function isValidTutorialPowerUpTarget(game, row, col) {
200→    const currentSwap = getCurrentTutorialSwap(game);
201→    if (!currentSwap || !currentSwap.powerUp) return false;
202→
203→    const target = currentSwap.powerUp.target;
204→    return row === target.row && col === target.col;
205→}
206→
207→/**
208→ * Advance to the next tutorial step or complete tutorial
209→ * @param {Match3Game} game - Game instance
210→ */
211→export function advanceTutorialStep(game) {
212→    if (!isTutorialActive(game)) return;
213→
214→    game.tutorialState.currentStep++;
215→
216→    // Check if there are more steps
217→    if (game.tutorialState.currentStep >= game.tutorialState.swaps.length) {
218→        completeTutorial(game);
219→    } else {
220→        // Update UI for next step
221→        const currentSwap = getCurrentTutorialSwap(game);
222→        const isPowerUpTutorial = currentSwap && currentSwap.powerUp;
223→
224→        // Show/hide power-ups based on next step type
225→        const powerUpsContainer = document.getElementById("bottom-container");
226→        if (powerUpsContainer) {
227→            powerUpsContainer.style.visibility = isPowerUpTutorial ? "" : "hidden";
228→        }
229→
230→        updateTutorialUI(game);
231→    }
232→}
233→
234→/**
235→ * Complete tutorial and return to normal gameplay
236→ * @param {Match3Game} game - Game instance
237→ */
238→export function completeTutorial(game) {
239→    if (!game.tutorialState) return;
240→
241→    game.tutorialState.active = false;
242→    hideTutorialUI(game);
243→}
244→
245→/**
246→ * Show tutorial UI with hand animation and hint text
247→ * @param {Match3Game} game - Game instance
248→ */
249→export function showTutorialUI(game) {
250→    if (!isTutorialActive(game) || !game.tutorialElements) return;
251→
252→    const { overlay } = game.tutorialElements;
253→    overlay.classList.remove("hidden");
254→
255→    // Hide power-ups during tutorial UNLESS it's a power-up tutorial step
256→    const currentSwap = getCurrentTutorialSwap(game);
257→    const isPowerUpTutorial = currentSwap && currentSwap.powerUp;
258→
259→    const powerUpsContainer = document.getElementById("bottom-container");
260→    if (powerUpsContainer && !isPowerUpTutorial) {
261→        powerUpsContainer.style.visibility = "hidden";
262→    } else if (powerUpsContainer && isPowerUpTutorial) {
263→        powerUpsContainer.style.visibility = "";
264→    }
265→
266→    updateTutorialUI(game);
267→}
268→
269→/**
270→ * Update tutorial UI for current step
271→ * @param {Match3Game} game - Game instance
272→ */
273→export function updateTutorialUI(game) {
274→    const currentSwap = getCurrentTutorialSwap(game);
275→    if (!currentSwap) return;
276→
277→    const { hintText, hintBox } = game.tutorialElements;
278→
279→    // Update hint text
280→    hintText.textContent = currentSwap.text;
281→
282→    // Position hint box based on step type
283→    if (currentSwap.powerUp && !game.activePowerUp) {
284→        // Power-up step BEFORE activation - position above power-ups
285→        if (hintBox) {
286→            hintBox.style.bottom = "25vh"; // Above the power-ups
287→        }
288→    } else {
289→        // All other steps - position at bottom
290→        if (hintBox) {
291→            hintBox.style.bottom = "6vh";
292→        }
293→    }
294→
295→    // Update hand animation based on step type
296→    if (currentSwap.powerUp) {
297→        // Power-up tutorial step - show tap on power-up button, then tap on tile
298→        updateTutorialPowerUpAnimation(game, currentSwap.powerUp);
299→    } else if (currentSwap.tap) {
300→        // Tap-only step
301→        updateTutorialTapAnimation(game, currentSwap.tap);
302→    } else if (currentSwap.from && currentSwap.to) {
303→        // Swap step
304→        updateTutorialSwapAnimation(game, currentSwap.from, currentSwap.to);
305→    }
306→}
307→
308→/**
309→ * Hide tutorial UI elements
310→ * @param {Match3Game} game - Game instance
311→ */
312→export function hideTutorialUI(game) {
313→    if (!game.tutorialElements) return;
314→
315→    const { overlay, hand } = game.tutorialElements;
316→
317→    hand.classList.remove("animating-swipe", "animating-tap");
318→    overlay.classList.add("hidden");
319→
320→    // Show power-ups again after tutorial
321→    const powerUpsContainer = document.getElementById("bottom-container");
322→    if (powerUpsContainer) {
323→        powerUpsContainer.style.visibility = "";
324→    }
325→}
