327→/**
328→ * Position and animate the tutorial hand for swipe gesture
329→ * @param {Match3Game} game - Game instance
330→ * @param {Object} fromCell - {row, col} starting cell
331→ * @param {Object} toCell - {row, col} destination cell
332→ */
333→function updateTutorialSwapAnimation(game, fromCell, toCell) {
334→    if (!game.tutorialElements) return;
335→
336→    const { hand } = game.tutorialElements;
337→
338→    // Query DOM for cell elements
339→    const fromElement = document.querySelector(`.gem[data-row="${fromCell.row}"][data-col="${fromCell.col}"]`);
340→    const toElement = document.querySelector(`.gem[data-row="${toCell.row}"][data-col="${toCell.col}"]`);
341→
342→    if (!fromElement || !toElement) {
343→        console.warn("Tutorial: Could not find cell elements", fromCell, toCell);
344→        return;
345→    }
346→
347→    // Get bounding rectangles
348→    const fromRect = fromElement.getBoundingClientRect();
349→    const toRect = toElement.getBoundingClientRect();
350→
351→    // Calculate center positions
352→    const fromCenterX = fromRect.left + fromRect.width / 2;
353→    const fromCenterY = fromRect.top + fromRect.height / 2;
354→    const toCenterX = toRect.left + toRect.width / 2;
355→    const toCenterY = toRect.top + toRect.height / 2;
356→
357→    // Calculate delta for animation
358→    const dx = toCenterX - fromCenterX;
359→    const dy = toCenterY - fromCenterY;
360→
361→    // Position hand at from cell center
362→    hand.style.left = `${fromCenterX}px`;
363→    hand.style.top = `${fromCenterY}px`;
364→
365→    // Set CSS custom properties for animation
366→    hand.style.setProperty("--hand-dx", `${dx}px`);
367→    hand.style.setProperty("--hand-dy", `${dy}px`);
368→
369→    // Remove tap animation and add swipe animation
370→    hand.classList.remove("hidden", "animating-tap");
371→    hand.classList.add("animating-swipe");
372→}
373→
374→/**
375→ * Position and animate the tutorial hand for tap gesture
376→ * @param {Match3Game} game - Game instance
377→ * @param {Object} tapCell - {row, col} cell to tap
378→ */
379→function updateTutorialTapAnimation(game, tapCell) {
380→    if (!game.tutorialElements) return;
381→
382→    const { hand } = game.tutorialElements;
383→
384→    // Query DOM for cell element
385→    const tapElement = document.querySelector(`.gem[data-row="${tapCell.row}"][data-col="${tapCell.col}"]`);
386→
387→    if (!tapElement) {
388→        console.warn("Tutorial: Could not find tap cell element", tapCell);
389→        return;
390→    }
391→
392→    // Get bounding rectangle
393→    const tapRect = tapElement.getBoundingClientRect();
394→
395→    // Calculate center position
396→    const centerX = tapRect.left + tapRect.width / 2;
397→    const centerY = tapRect.top + tapRect.height / 2;
398→
399→    // Position hand at cell center
400→    hand.style.left = `${centerX}px`;
401→    hand.style.top = `${centerY}px`;
402→
403→    // Remove swipe animation and add tap animation
404→    hand.classList.remove("hidden", "animating-swipe");
405→    hand.classList.add("animating-tap");
406→}
407→
408→/**
409→ * Position and animate the tutorial hand for power-up usage
410→ * @param {Match3Game} game - Game instance
411→ * @param {Object} powerUpConfig - {type: "hammer"|"halve"|"swap", target: {row, col}}
412→ */
413→function updateTutorialPowerUpAnimation(game, powerUpConfig) {
414→    if (!game.tutorialElements) return;
415→
416→    const { hand } = game.tutorialElements;
417→
418→    // If power-up is not active, show hand on power-up button
419→    if (!game.activePowerUp || game.activePowerUp !== powerUpConfig.type) {
420→        const powerUpButton = document.querySelector(`[data-powerup="${powerUpConfig.type}"]`);
421→
422→        if (!powerUpButton) {
423→            console.warn("Tutorial: Could not find power-up button", powerUpConfig.type);
424→            return;
425→        }
426→
427→        // Get bounding rectangle
428→        const buttonRect = powerUpButton.getBoundingClientRect();
429→
430→        // Calculate center position
431→        const centerX = buttonRect.left + buttonRect.width / 2;
432→        const centerY = buttonRect.top + buttonRect.height / 2;
433→
434→        // Position hand at button center
435→        hand.style.left = `${centerX}px`;
436→        hand.style.top = `${centerY}px`;
437→
438→        // Add tap animation
439→        hand.classList.remove("hidden", "animating-swipe");
440→        hand.classList.add("animating-tap");
441→    } else {
442→        // Power-up is active, show hand on target tile
443→        const targetElement = document.querySelector(
444→            `.gem[data-row="${powerUpConfig.target.row}"][data-col="${powerUpConfig.target.col}"]`
445→        );
446→
447→        if (!targetElement) {
448→            console.warn("Tutorial: Could not find target tile element", powerUpConfig.target);
449→            return;
450→        }
451→
452→        // Get bounding rectangle
453→        const targetRect = targetElement.getBoundingClientRect();
454→
455→        // Calculate center position
456→        const centerX = targetRect.left + targetRect.width / 2;
457→        const centerY = targetRect.top + targetRect.height / 2;
458→
459→        // Position hand at tile center
460→        hand.style.left = `${centerX}px`;
461→        hand.style.top = `${centerY}px`;
462→
463→        // Add tap animation
464→        hand.classList.remove("hidden", "animating-swipe");
465→        hand.classList.add("animating-tap");
466→    }
467→}
