  1→/**
  2→ * StrokedText Web Component
  3→ * Displays text with a customizable stroke outline using SVG
  4→ *
  5→ * Attributes:
  6→ * - text: The text to display
  7→ * - font-size: Font size (default: 32)
  8→ * - fill: Fill color (default: #fff)
  9→ * - stroke: Stroke color (default: #000)
 10→ * - stroke-width: Stroke width (default: 6)
 11→ * - width: SVG viewBox width (optional, auto-calculated based on text length if not provided)
 12→ * - height: SVG viewBox height (optional, auto-calculated as fontSize * 1.35 if not provided)
 13→ * - font-weight: Font weight (default: 900)
 14→ * - text-anchor: Text anchor position (default: middle)
 15→ * - svg-style: Additional styles for the SVG element (optional)
 16→ */
 17→class StrokedText extends HTMLElement {
 18→    constructor() {
 19→        super();
 20→        this.attachShadow({ mode: "open" });
 21→    }
 22→
 23→    connectedCallback() {
 24→        this.render();
 25→    }
 26→
 27→    static get observedAttributes() {
 28→        return ["text", "font-size", "fill", "stroke", "stroke-width", "width", "height", "font-weight", "text-anchor"];
 29→    }
 30→
 31→    attributeChangedCallback() {
 32→        if (this.shadowRoot.children.length > 0) {
 33→            this.render();
 34→        }
 35→    }
 36→
 37→    // Check if text contains emoji characters
 38→    containsEmoji(text) {
 39→        const emojiRegex =
 40→            /[\u{1F600}-\u{1F64F}]|[\u{1F300}-\u{1F5FF}]|[\u{1F680}-\u{1F6FF}]|[\u{1F1E0}-\u{1F1FF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]|[\u{1F900}-\u{1F9FF}]|[\u{1FA00}-\u{1FA6F}]|[\u{1FA70}-\u{1FAFF}]|[\u{231A}-\u{231B}]|[\u{23E9}-\u{23F3}]|[\u{23F8}-\u{23FA}]|[\u{25AA}-\u{25AB}]|[\u{25B6}]|[\u{25C0}]|[\u{25FB}-\u{25FE}]|[\u{2614}-\u{2615}]|[\u{2648}-\u{2653}]|[\u{267F}]|[\u{2693}]|[\u{26A1}]|[\u{26AA}-\u{26AB}]|[\u{26BD}-\u{26BE}]|[\u{26C4}-\u{26C5}]|[\u{26CE}]|[\u{26D4}]|[\u{26EA}]|[\u{26F2}-\u{26F3}]|[\u{26F5}]|[\u{26FA}]|[\u{26FD}]|[\u{2702}]|[\u{2705}]|[\u{2708}-\u{270D}]|[\u{270F}]|[\u{2712}]|[\u{2714}]|[\u{2716}]|[\u{271D}]|[\u{2721}]|[\u{2728}]|[\u{2733}-\u{2734}]|[\u{2744}]|[\u{2747}]|[\u{274C}]|[\u{274E}]|[\u{2753}-\u{2755}]|[\u{2757}]|[\u{2763}-\u{2764}]|[\u{2795}-\u{2797}]|[\u{27A1}]|[\u{27B0}]|[\u{27BF}]|[\u{2934}-\u{2935}]|[\u{2B05}-\u{2B07}]|[\u{2B1B}-\u{2B1C}]|[\u{2B50}]|[\u{2B55}]|[\u{3030}]|[\u{303D}]|[\u{3297}]|[\u{3299}]/u;
 41→        return emojiRegex.test(text);
 42→    }
 43→
 44→    render() {
 45→        const text = this.getAttribute("text") || "";
 46→        const fontSize = Number(this.getAttribute("font-size") || "32");
 47→        const fill = this.getAttribute("fill") || "#fff";
 48→        const stroke = this.getAttribute("stroke") || "#000";
 49→        const strokeWidth = Number(this.getAttribute("stroke-width") || "6");
 50→        const fontWeight = this.getAttribute("font-weight") || "900";
 51→        const textAnchor = this.getAttribute("text-anchor") || "middle";
 52→        const svgStyle = this.getAttribute("svg-style") || "";
 53→
 54→        // Check if text contains emojis - use canvas-based approach for emojis
 55→        const hasEmoji = this.containsEmoji(text);
 56→
 57→        // Calculate dimensions if not provided
 58→        // Height is based on font size + stroke padding
 59→        const height = Number(this.getAttribute("height")) || fontSize * 1.35;
 60→
 61→        // Width estimation: ~0.6 * fontSize per character on average for Nunito
 62→        // Add padding for stroke width on both sides
 63→        const estimatedTextWidth = text.length * fontSize * 0.6;
 64→        const padding = strokeWidth * 2;
 65→        const width = Number(this.getAttribute("width")) || estimatedTextWidth + padding;
 66→
 67→        // Calculate center position based on text anchor
 68→        const x = textAnchor === "middle" ? width / 2 : textAnchor === "end" ? width - strokeWidth : 0;
 69→        const y = height * 0.75; // Position text vertically centered
 70→
 71→        // For emojis, render to canvas first to get proper pixel data
 72→        if (hasEmoji) {
 73→            this.renderEmojiWithCanvas(text, fontSize, stroke, strokeWidth, width, height, svgStyle);
 74→            return;
 75→        }
 76→
 77→        this.shadowRoot.innerHTML = `
 78→            <style>
 79→                :host {
 80→                    display: inline-block;
 81→                }
 82→                svg {
 83→                    display: block;
 84→                    font-family: "Nunito", system-ui, -apple-system, sans-serif;
 85→                    ${svgStyle}
 86→                }
 87→            </style>
 88→            <svg viewBox="0 0 ${width} ${height}" width="${width}" height="${height}">
 89→                <text
 90→                    x="${x}"
 91→                    y="${y}"
 92→                    font-size="${fontSize}"
 93→                    font-weight="${fontWeight}"
 94→                    fill="${fill}"
 95→                    stroke="${stroke}"
 96→                    stroke-width="${strokeWidth}"
 97→                    paint-order="stroke fill"
 98→                    stroke-linejoin="round"
 99→                    text-anchor="${textAnchor}"
100→                >
101→                    ${text}
102→                </text>
103→            </svg>
104→        `;
105→    }
106→
107→    renderEmojiWithCanvas(text, fontSize, stroke, strokeWidth, width, height, svgStyle) {
108→        // Use higher resolution for crisp rendering
109→        const scale = 4;
110→        const scaledFontSize = fontSize * scale;
111→        const scaledStrokeWidth = strokeWidth * scale;
112→
113→        // Minimal padding just for the stroke
114→        const padding = scaledStrokeWidth;
115→        const canvasSize = scaledFontSize + padding * 2;
116→
117→        // Vertical offset to center emoji better (emojis often sit high)
118→        const verticalOffset = scaledFontSize * 0.15;
119→
120→        // Create offscreen canvas to draw emoji
121→        const emojiCanvas = document.createElement("canvas");
122→        emojiCanvas.width = canvasSize;
123→        emojiCanvas.height = canvasSize;
124→        const emojiCtx = emojiCanvas.getContext("2d");
125→
126→        // Draw emoji centered
127→        emojiCtx.font = `${scaledFontSize}px "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji", sans-serif`;
128→        emojiCtx.textAlign = "center";
129→        emojiCtx.textBaseline = "middle";
130→        emojiCtx.fillText(text, canvasSize / 2, canvasSize / 2 + verticalOffset);
131→
132→        // Create the final canvas with stroke
133→        const finalCanvas = document.createElement("canvas");
134→        finalCanvas.width = canvasSize;
135→        finalCanvas.height = canvasSize;
136→        const finalCtx = finalCanvas.getContext("2d");
137→
138→        // Draw the stroke by drawing the emoji multiple times offset in all directions
139→        finalCtx.font = `${scaledFontSize}px "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji", sans-serif`;
140→        finalCtx.textAlign = "center";
141→        finalCtx.textBaseline = "middle";
142→
143→        // Parse stroke color first
144→        const tempDiv = document.createElement("div");
145→        tempDiv.style.color = stroke;
146→        document.body.appendChild(tempDiv);
147→        const computedColor = getComputedStyle(tempDiv).color;
148→        document.body.removeChild(tempDiv);
149→        const rgbMatch = computedColor.match(/(\d+)/g);
150→        const strokeR = parseInt(rgbMatch[0]);
151→        const strokeG = parseInt(rgbMatch[1]);
152→        const strokeB = parseInt(rgbMatch[2]);
153→
154→        // Create stroke effect by drawing in a circle pattern at multiple radii for smoothness
155→        const strokeRadius = scaledStrokeWidth / 2;
156→        const steps = 32; // More steps for smoother circle
157→        const radiusSteps = 3; // Draw at multiple radii for filled stroke
158→
159→        for (let r = 1; r <= radiusSteps; r++) {
160→            const currentRadius = (strokeRadius * r) / radiusSteps;
161→            for (let i = 0; i < steps; i++) {
162→                const angle = (i / steps) * Math.PI * 2;
163→                const offsetX = Math.cos(angle) * currentRadius;
164→                const offsetY = Math.sin(angle) * currentRadius;
165→
166→                finalCtx.save();
167→                finalCtx.translate(offsetX, offsetY);
168→                finalCtx.fillText(text, canvasSize / 2, canvasSize / 2 + verticalOffset);
169→                finalCtx.restore();
170→            }
171→        }
172→
173→        // Convert to stroke color - preserve alpha for anti-aliasing
174→        const imageData = finalCtx.getImageData(0, 0, canvasSize, canvasSize);
175→        const data = imageData.data;
176→
177→        // Replace colors but preserve alpha for smooth edges
178→        for (let i = 0; i < data.length; i += 4) {
179→            if (data[i + 3] > 0) {
180→                data[i] = strokeR;
181→                data[i + 1] = strokeG;
182→                data[i + 2] = strokeB;
183→                // Keep original alpha for anti-aliasing
184→            }
185→        }
186→        finalCtx.putImageData(imageData, 0, 0);
187→
188→        // Draw the original emoji on top
189→        finalCtx.drawImage(emojiCanvas, 0, 0);
190→
191→        // Get the final image as a data URL
192→        const finalDataUrl = finalCanvas.toDataURL("image/png");
193→
194→        // Display size matches the canvas proportions
195→        const imageSize = fontSize + strokeWidth;
196→
197→        this.shadowRoot.innerHTML = `
198→            <style>
199→                :host {
200→                    display: inline-flex;
201→                    align-items: center;
202→                    justify-content: center;
203→                    width: ${width}px;
204→                    height: ${height}px;
205→                }
206→                img {
207→                    display: block;
208→                    width: ${imageSize}px;
209→                    height: ${imageSize}px;
210→                    ${svgStyle}
211→                }
212→            </style>
213→            <img src="${finalDataUrl}" alt="${text}" />
214→        `;
215→    }
216→}
