15→        const rect1 = gem1.getBoundingClientRect();
16→        const rect2 = gem2.getBoundingClientRect();
17→
18→        const deltaX = rect2.left - rect1.left;
19→        const deltaY = rect2.top - rect1.top;
20→
21→        // Animate both gems swapping positions
22→        gem1.style.transform = `translate(${deltaX}px, ${deltaY}px)`;
23→        gem2.style.transform = `translate(${-deltaX}px, ${-deltaY}px)`;
24→        gem1.style.transition = "transform 0.3s ease-out";
