34→            gem2.style.transition = "";
35→            gem1.style.zIndex = "";
36→            gem2.style.zIndex = "";
37→
38→            // Execute callback (render board and process matches)
39→            // Note: callback (processMatches) will handle setting this.animating = false
40→            if (callback) callback();
