  8→function registerServiceWorker() {
  9→    if ("serviceWorker" in navigator) {
 10→        const isLocalhost =
 11→            location.hostname === "localhost" ||
 12→            location.hostname === "127.0.0.1" ||
 13→            /^(\d{1,3}\.){3}\d{1,3}$/.test(location.hostname);
 14→        if (!isLocalhost) {
 15→            window.addEventListener("load", () => {
 16→                navigator.serviceWorker
 17→                    .register("sw.js", { updateViaCache: "none" })
 18→                    .then((reg) => {
 19→                        // Check for updates every time the page loads
 20→                        reg.update();
 21→                    })
 22→                    .catch(() => {
 23→                        // Silently fail if service worker registration fails
 24→                    });
 25→            });
 26→
 27→            // Listen for service worker updates
 28→            navigator.serviceWorker.addEventListener("message", (event) => {
 29→                if (event.data && event.data.type === "SW_UPDATED") {
 30→                    // Reload once to get the new version
 31→                    window.location.reload();
 32→                }
 33→            });
 34→        }
 35→    }
 36→}
 37→
 38→// Unregister all active service workers
 39→async function unregisterServiceWorkers() {
 40→    if ("serviceWorker" in navigator) {
 41→        const registrations = await navigator.serviceWorker.getRegistrations();
 42→        for (const registration of registrations) {
 43→            await registration.unregister();
 44→        }
 45→    }
 46→}
