 48→/**
 49→ * Check version and reset game if major version has changed or no version exists
 50→ * @returns {boolean} True if game was reset, false otherwise
 51→ */
 52→function checkVersionAndReset() {
 53→    const storedVersion = loadVersion();
 54→
 55→    // If no stored version exists, this is a new install or old version without version tracking
 56→    if (!storedVersion) {
 57→        console.log("No stored version found. Resetting game and saving version:", APP_VERSION);
 58→        localStorage.clear();
 59→        saveVersion(APP_VERSION);
 60→        return true;
 61→    }
 62→
 63→    // Parse major version from stored and current versions
 64→    const storedMajor = parseInt(storedVersion.split(".")[0], 10);
 65→    const currentMajor = parseInt(APP_VERSION.split(".")[0], 10);
 66→
 67→    // If major version has changed, reset the game
 68→    if (storedMajor !== currentMajor) {
 69→        console.log(`Major version changed from ${storedVersion} to ${APP_VERSION}. Resetting game.`);
 70→        localStorage.clear();
 71→        saveVersion(APP_VERSION);
 72→        return true;
 73→    }
 74→
 75→    // Update stored version to current version (for minor/patch updates)
 76→    if (storedVersion !== APP_VERSION) {
 77→        console.log(`Version updated from ${storedVersion} to ${APP_VERSION}`);
 78→        saveVersion(APP_VERSION);
 79→    }
 80→
 81→    return false;
 82→}
